import{readFile,writeFile}from"node:fs/promises";const CONNECT_CONNECTOR_REGEX=/(\bconnect\(\s*)(["'`])([^"'`]+)\2/;async function updateConnectionConnectorUid(r,i){let a;try{a=await readFile(r,`utf8`)}catch{return{patched:!1}}return CONNECT_CONNECTOR_REGEX.test(a)?(await writeFile(r,a.replace(CONNECT_CONNECTOR_REGEX,(e,t,n)=>`${t}${n}${i}${n}`),`utf8`),{patched:!0}):{patched:!1}}export{updateConnectionConnectorUid};